after_code.lib/libc/net/linkaddr.c::link_ntoa:
char *
link_ntoa(const struct sockaddr_dl *sdl)
{
	static char obuf[64];
	_Static_assert(sizeof(obuf) >= IFNAMSIZ + 20, "obuf is too small");
	char *out;
	const char *in, *inlim;
	int namelen, i, rem;

	namelen = (sdl->sdl_nlen <= IFNAMSIZ) ? sdl->sdl_nlen : IFNAMSIZ;

	out = obuf;
	rem = sizeof(obuf);
	if (namelen > 0) {
		bcopy(sdl->sdl_data, out, namelen);
		out += namelen;
		rem -= namelen;
		if (sdl->sdl_alen > 0) {
			*out++ = ':';
			rem--;
		}
	}

	in = (const char *)sdl->sdl_data + sdl->sdl_nlen;
	inlim = in + sdl->sdl_alen;

	while (in < inlim && rem > 1) {
		if (in != (const char *)sdl->sdl_data + sdl->sdl_nlen) {
			*out++ = '.';
			rem--;
		}
		i = *in++;
		if (i > 0xf) {
			if (rem < 3)
				break;
			*out++ = hexlist[i & 0xf];
			i >>= 4;
			*out++ = hexlist[i];
			rem -= 2;
		} else {
			if (rem < 2)
				break;
			*out++ = hexlist[i];
			rem++;
		}
	}
	*out = 0;
	return (obuf);
}

